<div class="en">
<svg viewBox="0 0 700 340" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:auto;background:#111113;border-radius:12px;border:1px solid rgba(255,255,255,.08);margin:20px 0">
  <text x="20" y="28" fill="#fafafa" font-size="16" font-weight="700" font-family="sans-serif">Bitcoin's Yen-Dollar Split (Jul 10) — By the Numbers</text>
  <g font-family="sans-serif">
    <text x="150" y="91" fill="#e4e4e7" font-size="13" text-anchor="end">BTC/USD (Nasdaq)</text>
    <rect x="160" y="70" width="460" height="36" rx="6" fill="#f7931a"/>
    <text x="596" y="93" fill="#0a0a0a" font-size="13" font-weight="700" text-anchor="end">+1.15%</text>

    <text x="150" y="141" fill="#e4e4e7" font-size="13" text-anchor="end">BTC/JPY (BitFlyer)</text>
    <rect x="160" y="120" width="272" height="36" rx="6" fill="#38bdf8"/>
    <text x="408" y="143" fill="#0a0a0a" font-size="13" font-weight="700" text-anchor="end">+0.68%</text>

    <rect x="20" y="190" width="320" height="100" rx="10" fill="#1c1c1f" stroke="#3f3f46" stroke-width="1.2"/>
    <text x="180" y="215" fill="#a1a1aa" font-size="13" text-anchor="middle">USD/JPY Rate</text>
